import React, { useState } from 'react';

const JobMatcher = ({ token }) => {
    const [description, setDescription] = useState('');
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);

    const analyze = async (e) => {
        e.preventDefault();
        setLoading(true);
        const res = await fetch('/api/ai/match-job', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': token
            },
            body: JSON.stringify({ description })
        });
        const data = await res.json();
        setResult(data);
        setLoading(false);
    };

    return (
        <div>
            <h1 style={{ marginBottom: '20px' }}>Job Match Analyzer</h1>
            
            <div className="grid-2">
                <div className="card">
                    <h3>Job Description</h3>
                    <form onSubmit={analyze}>
                        <textarea
                            rows="10"
                            placeholder="Paste job description here..."
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            required
                            style={{ width: '100%', padding: '10px' }}
                        />
                        <button type="submit" disabled={loading}>
                            {loading ? 'Analyzing...' : 'Analyze Match'}
                        </button>
                    </form>
                </div>

                <div className="card">
                    <h3>Match Results</h3>
                    {result ? (
                        <div>
                            <div style={{ textAlign: 'center', margin: '20px 0' }}>
                                <div style={{ fontSize: '48px', fontWeight: 'bold', color: result.score > 70 ? '#27ae60' : result.score > 40 ? '#f39c12' : '#e74c3c' }}>
                                    {result.score}%
                                </div>
                                <div>Match Score</div>
                            </div>
                            
                            <h4>Matching Skills:</h4>
                            <div style={{ marginBottom: '15px' }}>
                                {result.matchedSkills.length > 0 ? (
                                    result.matchedSkills.map((skill, i) => (
                                        <span key={i} style={{ display: 'inline-block', background: '#4a90e2', color: 'white', padding: '5px 10px', borderRadius: '5px', margin: '5px', fontSize: '12px' }}>
                                            {skill}
                                        </span>
                                    ))
                                ) : (
                                    <p>No matching skills found</p>
                                )}
                            </div>
                            
                            <h4>Suggestions:</h4>
                            <ul style={{ paddingLeft: '20px' }}>
                                {result.suggestions.map((s, i) => (
                                    <li key={i} style={{ marginBottom: '5px' }}>{s}</li>
                                ))}
                            </ul>
                        </div>
                    ) : (
                        <p style={{ color: '#999', textAlign: 'center', padding: '50px' }}>
                            Paste a job description to see how well it matches
                        </p>
                    )}
                </div>
            </div>
        </div>
    );
};

export default JobMatcher;
